import{Ct as e,ct as t,lt as n,q as r}from"./chunks/framework.BVmwMUcr.js";var i=JSON.parse(`{"title":"启程，华南理工大学！","description":"","frontmatter":{},"headers":[],"relativePath":"en/get-started.md","filePath":"en/get-started.md","lastUpdated":1784824103000}`),a={name:`en/get-started.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /en/get-started.md for this page in Markdown format</div><h1 id="启程-华南理工大学" tabindex="-1">启程，华南理工大学！ <a class="header-anchor" href="#启程-华南理工大学" aria-label="Permalink to “启程，华南理工大学！”">​</a></h1><p>—— 2026级本科新生入学指南</p><p>恭喜你考入华南理工大学！为了帮助你清晰规划行程、顺利完成报到并快速熟悉大学生活，编者根据最新公布的新生入学须知及手册各版块内容，整理了这份提炼版指南与实用提醒。华园期待你的到来！</p><p><strong>Tips：涉及户口转接、档案转接、团籍转接等重大事项，及到校注册时间节点等，请以随录取通知书发放的新生入学指南为准！务必再三核对，谨遵官方信息！不明白的地方及时询问辅导员、班主任及临时班干！</strong></p><p>在开始前，推荐阅读：<a href="/health/freshman_guidance">你到大学，是来重新获得选择权的（新生建议）</a>。</p><hr><h2 id="入学关键时间线与清单-checklist" tabindex="-1">入学关键时间线与清单（Checklist） <a class="header-anchor" href="#入学关键时间线与清单-checklist" aria-label="Permalink to “入学关键时间线与清单（Checklist）”">​</a></h2><h3 id="timeline-关键时间线" tabindex="-1">Timeline / 关键时间线 <a class="header-anchor" href="#timeline-关键时间线" aria-label="Permalink to “Timeline / 关键时间线”">​</a></h3><ul><li><strong>8月中旬</strong>：迎新系统开通。登录系统激活统一认证账号、绑定微信企业号、完成个人信息采集。</li><li><strong>8月22日 8:00 - 9月1日 8:00</strong>：开放深夜接站申请（仅限9月4日-5日深夜抵穗且确有困难的同学）。</li><li><strong>8月29日之后</strong>：若纸质档案选择邮寄，请在此日期后通过中国邮政 EMS 寄出。</li><li><strong>9月5日 - 9月6日（8:30 - 17:30）</strong>：新生正式到校报到。办理宿舍入住，并在校园内通过 MyPass 系统完成线上定位与人脸识别报到注册。</li><li><strong>9月9日 - 9月13日</strong>：广州国际校区各专业二次选拔面试。</li></ul><h3 id="checklist-报到前检查单" tabindex="-1">Checklist / 报到前检查单 <a class="header-anchor" href="#checklist-报到前检查单" aria-label="Permalink to “Checklist / 报到前检查单”">​</a></h3><p><strong>随身携带材料</strong></p><ul><li>[ ] 录取通知书原件</li><li>[ ] 本人有效身份证原件（如遗失，须携带户口簿及有效期内的临时身份证）</li><li>[ ] 密封的高中阶段纸质档案（若选择自提带校）</li></ul><p><strong>线上完成事项</strong></p><ul><li>[ ] 迎新系统账号激活（绑定手机号与微信企业号）</li><li>[ ] 迎新系统个人信息采集完成</li><li>[ ] （可选）深夜接站网络申请（截止至9月1日 8:00）</li><li>[ ] （可选）申请线上“绿色通道”缓交学杂费</li></ul><p><strong>到校现场完成事项</strong></p><ul><li>[ ] 凭通知书与身份证办理宿舍入住、领取钥匙</li><li>[ ] 在校内登录 MyPass 系统完成“开学报到”（定位 + 人脸识别）</li><li>[ ] 提交纸质档案与党团关系材料（按所在院系安排）</li></ul><hr><h2 id="一、-报到时间与校区分布" tabindex="-1">一、 报到时间与校区分布 <a class="header-anchor" href="#一、-报到时间与校区分布" aria-label="Permalink to “一、 报到时间与校区分布”">​</a></h2><h3 id="_1-报到时间" tabindex="-1">1. 报到时间 <a class="header-anchor" href="#_1-报到时间" aria-label="Permalink to “1. 报到时间”">​</a></h3><p><strong>2026年9月5日 - 9月6日（星期六、星期日） 8:30 - 17:30</strong><br> 注：因特殊原因不能按时到校者，须事先书面并附相关证明向所在院系请假（原则上请假不超过两周）。</p><h3 id="_2-报到校区一览" tabindex="-1">2. 报到校区一览 <a class="header-anchor" href="#_2-报到校区一览" aria-label="Permalink to “2. 报到校区一览”">​</a></h3><p>欲了解三校区布局与基础设施，请参阅 <a href="/infra/">华园概览</a>。</p><table tabindex="0"><thead><tr><th style="text-align:left;">报到校区</th><th style="text-align:left;">涵盖学院 / 院系</th><th style="text-align:left;">校区地址与指南</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>五山校区</strong></td><td style="text-align:left;">建筑学院（不含百步梯创新学院学生）、体育学院</td><td style="text-align:left;">广州市天河区五山路381号（<a href="/infra/wushan/map">五山校区指南</a>）</td></tr><tr><td style="text-align:left;"><strong>广州国际校区</strong></td><td style="text-align:left;">生物医学科学与工程学院、吴贤铭智能工程学院、前沿软物质学院、微电子学院/集成电路学院、未来技术学院、海洋科学与工程学院</td><td style="text-align:left;">广州市番禺区兴业大道东777号（<a href="/infra/gzic/map">国际校区指北</a>）</td></tr><tr><td style="text-align:left;"><strong>大学城校区</strong></td><td style="text-align:left;">除上述学院外的其他所有院系</td><td style="text-align:left;">广州市番禺区大学城外环东路382号（<a href="/infra/hemc/map">大学城指南</a>）</td></tr></tbody></table><hr><h2 id="二、-报到准备与线上流程" tabindex="-1">二、 报到准备与线上流程 <a class="header-anchor" href="#二、-报到准备与线上流程" aria-label="Permalink to “二、 报到准备与线上流程”">​</a></h2><h3 id="_1-第一步-个人账号激活与信息采集-建议8月中旬完成" tabindex="-1">1. 第一步：个人账号激活与信息采集（建议8月中旬完成） <a class="header-anchor" href="#_1-第一步-个人账号激活与信息采集-建议8月中旬完成" aria-label="Permalink to “1. 第一步：个人账号激活与信息采集（建议8月中旬完成）”">​</a></h3><ol><li>访问 <a href="https://freshman.scut.edu.cn" target="_blank" rel="noreferrer">华工迎新系统</a>。</li><li>使用<strong>考生号</strong>（通知书条形码下方数字）和身份证号激活<strong>统一认证账号</strong>，并绑定手机号。</li><li>登录系统完成个人信息采集，并按指引微信扫码绑定“华南理工大学微信企业号”。</li></ol><h3 id="_2-第二步-来校当天-mypass-现场自助报到" tabindex="-1">2. 第二步：来校当天“MyPass”现场自助报到 <a class="header-anchor" href="#_2-第二步-来校当天-mypass-现场自助报到" aria-label="Permalink to “2. 第二步：来校当天“MyPass”现场自助报到”">​</a></h3><p>到达宿舍办理入住后，在报到当天登录 MyPass 系统（通过微信企业号或访问 <a href="https://enroll.scut.edu.cn/door/index_h5.html" target="_blank" rel="noreferrer">MyPass系统</a>）：</p><ul><li><strong>报到条件</strong>：必须同时满足 <strong>“手机定位在学校范围内”</strong> + <strong>“人脸识别成功”</strong>。</li><li><strong>具体流程</strong>：进入 MyPass → 点击“开学报到” → 开始采集 → 拍照提交 → 刷新查看“已报到”状态。</li></ul><blockquote><p><strong>提示</strong>：</p><ol><li>报到成功后，缴费注册状态会有半天至一天的系统更新延迟，无需另行操作。</li><li>如人脸识别多次尝试失败，可及时联系院系辅导员或现场志愿者协助进行辅助报到。</li></ol></blockquote><hr><h2 id="三、-交通与深夜接站指引" tabindex="-1">三、 交通与深夜接站指引 <a class="header-anchor" href="#三、-交通与深夜接站指引" aria-label="Permalink to “三、 交通与深夜接站指引”">​</a></h2><h3 id="_1-官方深夜接站安排" tabindex="-1">1. 官方深夜接站安排 <a class="header-anchor" href="#_1-官方深夜接站安排" aria-label="Permalink to “1. 官方深夜接站安排”">​</a></h3><p>接站仅面向 <strong>9月4日-5日深夜时段抵穗入校</strong> 且确有困难的新生及家长：</p><ul><li><strong>深夜接站时间</strong>： <ul><li>2026年9月4日 22:30 至 9月5日 05:30</li><li>2026年9月5日 22:30 至 9月6日 05:30</li></ul></li><li><strong>申请时间</strong>：8月22日 8:00 至 9月1日 8:00（请提前在迎新系统或 MyPass 模块提交申请）。</li></ul><h3 id="_2-各校区公共交通路线" tabindex="-1">2. 各校区公共交通路线 <a class="header-anchor" href="#_2-各校区公共交通路线" aria-label="Permalink to “2. 各校区公共交通路线”">​</a></h3><blockquote><p>常用跨校区出行及作息查询：</p><ul><li>跨校区公共交通与教工/学生车路线：查看 <a href="/life/time/bus">校巴时刻表</a></li><li>上课节次与时间对照表：查看 <a href="/life/time/wushan">五山时间</a> | <a href="/life/time/hemc_gzic">国际/大学城时间</a></li></ul></blockquote><details><summary><strong>点击展开：五山校区交通路线指南</strong></summary><ul><li><strong>公交车</strong>： <ul><li>华工大总站：32路、230路、775路、大学城专线2路</li><li>华工大站：20路、218路、B10路、78路、78A路、197路、405路、775路</li></ul></li><li><strong>地铁</strong>： <ul><li>3号线<strong>五山站C出口</strong>，出站右转步行约200米即达学校东门。</li></ul></li><li><strong>主要枢纽路线</strong>： <ul><li><strong>广州南站</strong>：地铁2号线（昌岗站）→ 8号线（客村站）→ 3号线（五山站）</li><li><strong>白云机场</strong>：地铁3号线北延段（体育西路站）→ 3号线（五山站）</li><li><strong>广州火车站</strong>：地铁11号线（华师站）→ 3号线（五山站）</li></ul></li></ul></details><details><summary><strong>点击展开：大学城校区交通路线指南</strong></summary><ul><li><strong>公交车</strong>： <ul><li>华工站 / 华工生活区站：大学城环线1路、387路、番201路、番202路</li><li>华工正门站：番87路</li></ul></li><li><strong>地铁</strong>： <ul><li>4号线 / 7号线<strong>大学城南站D出口</strong>，往北直走约500米到达生活区。</li></ul></li><li><strong>主要枢纽路线</strong>： <ul><li><strong>广州南站</strong>：地铁7号线直达（大学城南站）</li><li><strong>天河客运站</strong>：地铁3号线（汉溪长隆站）→ 7号线（大学城南站）</li><li><strong>广州火车站</strong>：地铁5号线（车陂南站）→ 4号线（大学城南站）</li><li><strong>白云机场</strong>：地铁3号线（汉溪长隆站）→ 7号线（大学城南站）</li></ul></li></ul></details><details><summary><strong>点击展开：广州国际校区交通路线指南</strong></summary><ul><li><strong>公交与接驳</strong>： <ul><li><strong>地铁换乘</strong>：地铁4号线<strong>新造站A出口</strong>，换乘<strong>番87路</strong>公交直达校区内；或地铁7号线<strong>板桥站A出口</strong>，换乘<strong>番72路</strong>公交到华工广州国际校区北门站。</li><li><strong>校区始发公交</strong>：番10路、番17路、番87路</li></ul></li><li><strong>主要枢纽路线</strong>： <ul><li><strong>广州南站</strong>：地铁7号线（板桥站A口）→ 换乘番72路公交</li><li><strong>白云机场T2</strong>：地铁3号线（汉溪长隆站）→ 7号线（板桥站A口）→ 换乘番72路公交</li><li><strong>大学城校区 ↔ 广州国际校区</strong>：华工正门站乘坐<strong>番87路</strong>可直达广州国际校区。</li></ul></li><li><strong>自驾定位</strong>：华南理工大学广州国际校区北大门 或 南大门。</li></ul></details><hr><h2 id="四、-入学后注意事项与生活提醒" tabindex="-1">四、 入学后注意事项与生活提醒 <a class="header-anchor" href="#四、-入学后注意事项与生活提醒" aria-label="Permalink to “四、 入学后注意事项与生活提醒”">​</a></h2><h3 id="_1-校园交通规范-重点" tabindex="-1">1. 校园交通规范（重点） <a class="header-anchor" href="#_1-校园交通规范-重点" aria-label="Permalink to “1. 校园交通规范（重点）”">​</a></h3><p>根据《华南理工大学电动自行车管理办法》，<strong>新生严禁购置个人电动自行车</strong>。 校内配备有自行车、校园共享电动车以及校园穿梭巴士，能够充分满足日常出行需要。</p><h3 id="_2-广州国际校区二次选拔与转专业规划" tabindex="-1">2. 广州国际校区二次选拔与转专业规划 <a class="header-anchor" href="#_2-广州国际校区二次选拔与转专业规划" aria-label="Permalink to “2. 广州国际校区二次选拔与转专业规划”">​</a></h3><ul><li><strong>二次选拔</strong>：计划参加广州国际校区各专业二次选拔的同学，学校将于 <strong>9月9日 - 9月13日</strong> 组织二次选拔面试。请提前查阅迎新系统或本科生院网站通知。</li><li><strong>转专业认知</strong>：若入学后有转专业规划，建议提前阅读 <a href="/learn/curricular/transfer_major_quick">华工转专业的快速认知</a> 及 <a href="/learn/curricular/transfer_major">转专业总览</a>（内含 <a href="/learn/curricular/transfer_major_2024">2024版转专业指南</a>、<a href="/learn/curricular/transfer_major_electrical_2026">转电气经验</a> 与 <a href="/learn/curricular/transfer_major_information_engineering_2026">转信工经验</a>）。</li></ul><h3 id="_3-学业、日常生活与医保服务" tabindex="-1">3. 学业、日常生活与医保服务 <a class="header-anchor" href="#_3-学业、日常生活与医保服务" aria-label="Permalink to “3. 学业、日常生活与医保服务”">​</a></h3><details><summary><strong>点击展开：校医院就医、饮食美德与学业规则指引</strong></summary><ul><li><strong>医疗与医保报销</strong>： <ul><li>参保学生普通门诊首诊在校医院，报销比例最高达 90%；外诊转诊报销流程及定点医院清单，详见 <a href="/health/medical_care">华南理工大学就医贴</a>。</li></ul></li><li><strong>校内与周边美食</strong>： <ul><li><a href="/life/eat/wushan">五山觅食指南</a> | <a href="/life/eat/hemc">大学城觅食指南</a> | <a href="/life/eat/gzic">国际校区觅食指南</a></li></ul></li><li><strong>学业与成绩规则</strong>： <ul><li>必修、选修、通识课怎么算？参见 <a href="/learn/curricular/lessons">课程性质介绍</a>。</li><li>均分、GPA 与综测分有何区别？参见 <a href="/learn/curricular/gpa">GPA 与成绩规则详解</a>。</li><li>公共课学习建议：参阅 <a href="/learn/curricular/common_basic_lessons">公共课指南</a> 及 <a href="/learn/curricular/majors">专业课概览</a>。</li><li>创新学分与科研竞赛：了解 <a href="/learn/extra/innovation_humanities_scores">创新分与人文分要求</a>、<a href="/learn/extra/srp">SRP 科研项目</a> 及 <a href="/learn/extra/contest">竞赛目录及备赛建议</a>（如 <a href="/learn/extra/contest/cmc">全国大学生数学竞赛 CMC</a> 与 <a href="/learn/extra/contest/ACM">ACM 竞赛</a>）。</li></ul></li></ul></details><details><summary><strong>点击展开：档案邮寄、党团关系转接与校园卡充值</strong></summary><ul><li><strong>纸质档案</strong>： <ul><li>尽量携带密封档案自提报到，到校后交所在院系。</li><li>若须邮寄，<strong>请于8月29日之后</strong>通过 <strong>中国邮政 EMS</strong> 寄送，封面务必标注就读院系与“学生档案”字样。</li><li>咨询电话：五山 020-87110590 | 大学城 020-81182638 | 广州国际校区 020-81181667</li></ul></li><li><strong>团组织关系转接</strong>： <ul><li>入学班级建立后，统一通过广东“智慧团建”系统发起线上转接，接收组织选择“华南理工大学XX学院（系）团委”（国际校区学生选择对应书院团委）。</li></ul></li><li><strong>党员组织关系转接</strong>： <ul><li><strong>广东省内</strong>：由原党组织通过《广东省党务管理信息系统》线上发起，接收党组织选择“中共华南理工大学XX学院/系委员会”（海洋学院选广州国际校区党委；集成电路学院选微电子学院党委；能源学院选电力学院党委）。</li><li><strong>广东省外</strong>：优先通过全国党员数据交互平台线上转接；若无法线上转接，可携带纸质介绍信（抬头：<strong>华南理工大学党委</strong>）入学后交所在院系党委。</li></ul></li><li><strong>校园一卡通充值</strong>： <ul><li>打开微信企业号 → 校园一卡通 → 账号登录（初始密码为身份证后6位） → 卡片充值 → 微信支付。</li></ul></li></ul></details><h3 id="_4-安全、防诈与提问礼仪" tabindex="-1">4. 安全、防诈与提问礼仪 <a class="header-anchor" href="#_4-安全、防诈与提问礼仪" aria-label="Permalink to “4. 安全、防诈与提问礼仪”">​</a></h3><ul><li><strong>拒绝上门推销</strong>：宿舍区内如有人员上门推销电话卡、杂志、生活用品等，请保持警惕，一律拒绝。</li><li><strong>防范电信网络诈骗</strong>：凡涉及转账、刷单、充值解冻、假冒客服或安全账户的电话及短信，切勿轻信。如有疑问，请第一时间联系辅导员或迎新志愿者核实。</li><li><strong>提问的技巧</strong>：在向编者、老师或社群咨询问题前，推荐阅读 <a href="/others/ask-the-smart-way">提问的智慧</a>；如制作演示文稿或材料需要校徽资源，可前往 <a href="/others/branding">学校标识下载</a>。</li></ul><p>祝愿每一位2026级新同学在华南理工大学开启一段充实而美好的大学旅程！</p>`,54)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};